import anthropic

client = anthropic.Anthropic()

# Define tools as structured schemas — no regex parsing needed
tools = [
    {
        "name": "web_search",
        "description": "Search the web for current information.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "The search query"}
            },
            "required": ["query"],
        },
    },
    {
        "name": "calculator",
        "description": "Evaluate an arithmetic expression and return the result.",
        "input_schema": {
            "type": "object",
            "properties": {
                "expression": {
                    "type": "string",
                    "description": "A safe arithmetic expression, e.g. '(330 + 443) / 2'"
                }
            },
            "required": ["expression"],
        },
    },
]


def execute_tool(name: str, inputs: dict) -> str:
    """Route tool calls to actual implementations."""
    if name == "web_search":
        # In production: call a real search API (Tavily, Bing, SerpAPI)
        mock_results = {
            "eiffel tower height": "The Eiffel Tower is 330 metres tall.",
            "empire state building height": "The Empire State Building is 443 metres tall.",
        }
        q = inputs["query"].lower()
        for k, v in mock_results.items():
            if k in q:
                return v
        return "No relevant result found."
    elif name == "calculator":
        try:
            return str(eval(inputs["expression"]))  # demo only
        except Exception as e:
            return f"Error: {e}"
    return "Unknown tool."


def react_with_tools(question: str) -> str:
    """ReAct loop using Anthropic's native tool-use API."""
    messages = [{"role": "user", "content": question}]

    for step in range(8):
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=tools,
            messages=messages,
        )

        # Append assistant's response
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Extract final text answer
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return "[no text response]"

        if response.stop_reason == "tool_use":
            # Execute all tool calls and collect results
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = execute_tool(block.name, block.input)
                    print(f"[Step {step+1}] Tool: {block.name}({block.input}) → {result}")
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages.append({"role": "user", "content": tool_results})

    return "[max steps reached]"


answer = react_with_tools(
    "What is the average height of the Eiffel Tower and the Empire State Building?"
)
print(f"\nFinal answer: {answer}")
